// SKILL.md renderer — turns a validated WorkflowManifest into a Claude Code skill runbook.
//
// The generated skill is the Phase-1 executor: Claude reads it and drives the EXISTING MCP tools
// (get_capability → upload_file/process_file → execute_workflow → get_workflow_status → get_result)
// in the frozen order, substituting the user's per-run inputs for {{placeholders}}.
//
// Design notes:
//  • We re-validate each capability via get_capability at run time. This (a) satisfies execute_workflow's
//    "capability_id must come from get_capability this session" guard and (b) catches registry drift early.
//  • Fixed args are inlined verbatim; {{placeholder}} args are filled from the Inputs contract.
//  • depends_on/produces are surfaced so the run order is explicit and unambiguous.
function frontmatter(manifest) {
    // Description is single-line in YAML frontmatter — collapse any newlines.
    const desc = manifest.description.replace(/\s*\n\s*/g, " ").trim();
    return ["---", `name: ${manifest.slug}`, `description: ${desc}`, "---"].join("\n");
}
function renderInput(i) {
    const bits = [`**\`${i.key}\`** (${i.type}${i.required ? ", required" : ", optional"})`];
    bits.push(`— ${i.prompt}`);
    if (i.type === "enum" && i.values?.length)
        bits.push(`Allowed: ${i.values.map((v) => `\`${v}\``).join(", ")}.`);
    if (!i.required && i.default !== undefined)
        bits.push(`Default: \`${JSON.stringify(i.default)}\`.`);
    if (i.description)
        bits.push(i.description);
    return `- ${bits.join(" ")}`;
}
function renderStep(s, idx) {
    const lines = [`### Step ${idx + 1} — \`${s.id}\``];
    if (s.note)
        lines.push(`> ${s.note}`);
    lines.push("");
    lines.push(`- **capability_id**: \`${s.capability_id}\``);
    lines.push(`- **operation_id**: \`${s.operation_id}\``);
    if (s.depends_on.length)
        lines.push(`- **depends_on**: ${s.depends_on.map((d) => `\`${d}\``).join(", ")}`);
    if (s.produces)
        lines.push(`- **produces**: \`${s.produces}\` (referenceable by later steps)`);
    if (s.input_file_url)
        lines.push(`- **input_file_url**: \`${s.input_file_url}\``);
    if (s.args && Object.keys(s.args).length) {
        lines.push(`- **args**:`);
        lines.push("```json");
        lines.push(JSON.stringify(s.args, null, 2));
        lines.push("```");
    }
    if (s.config && Object.keys(s.config).length) {
        lines.push(`- **config**:`);
        lines.push("```json");
        lines.push(JSON.stringify(s.config, null, 2));
        lines.push("```");
    }
    return lines.join("\n");
}
function authBlock(manifest) {
    if (manifest.auth_mode === "3LO") {
        return ("This workflow needs a **user-identity (3LO) token**. Before the first `execute_workflow` call, run " +
            "`authenticate_aps_3lo` (opens a browser login; no confirmation needed). If any step returns " +
            "`3lo_required`, call it and retry that step with the same args.");
    }
    return ("This workflow uses **2LO** (client-credential) auth — `authenticate_aps` is auto-handled. " +
        "If a step unexpectedly returns `3lo_required`, call `authenticate_aps_3lo` then retry that step.");
}
export function renderSkillMd(manifest) {
    const fileInputs = manifest.inputs.filter((i) => i.type === "file_path");
    const distinctCaps = [...new Set(manifest.steps.map((s) => s.capability_id))];
    const inputsSection = manifest.inputs.length
        ? manifest.inputs.map(renderInput).join("\n")
        : "_This workflow takes no per-run inputs — every value is fixed._";
    const stepsSection = manifest.steps.map(renderStep).join("\n\n");
    const md = `${frontmatter(manifest)}

# ${manifest.name}

> Saved workflow skill generated by mcp-workflow-builder. Same execution, your inputs.

**What it does:** ${manifest.intent}

## Inputs

When invoked, collect these from the user (or from what they typed after the slash command). For any required input that is missing, ask for it before running. ${fileInputs.length
        ? "File-path inputs must be a real Mac path (`~/Downloads/`, a local folder, or OneDrive). Chat-attachment paths cannot be read by the server — if you get `bridge_required`, show `REQUIRED_ACTION` verbatim and ask for the actual path."
        : ""}

${inputsSection}

## How to run

Follow these steps in order. Substitute every \`{{placeholder}}\` with the matching input value.

1. **Re-validate the recipe.** For each capability below, call \`get_capability(capability_id=<id>)\` once to confirm it is still \`callable=true\`:
   ${distinctCaps.map((c) => `\`${c}\``).join(", ")}.
   If any returns \`callable=false\` or is not found, STOP and tell the user this saved workflow needs re-planning (the underlying capability changed) — do not improvise a substitute.
2. **Auth.** ${authBlock(manifest)}
3. ${fileInputs.length
        ? "**Upload the file once.** Call `upload_file(file_path=<the file_path input>)` and reuse the returned `oss://` URL as `input_file_url` for every step that needs it. Do NOT call `process_file` — that re-uploads per call."
        : "**No file upload needed** — this workflow has no file inputs."}
4. **Execute the steps in order**, respecting \`depends_on\`. For each step call:
   \`execute_workflow(capability_id, operation_id, args, input_file_url?)\`.
   - When a step \`produces\` an output and a later step references it, thread the producing step's \`oss://\` output URL into the consumer's \`input_file_url\`.
   - Engine-API steps return \`pending\` → poll \`get_workflow_status(workflow_handle)\` until \`success\`/\`failed\` (do not pause or ask). REST steps return inline.
5. **Collect results.** Call \`get_result\` on each output \`oss://\` URL (binaries auto-save to \`~/Downloads\`). Present the outputs to the user.

## The frozen recipe

${stepsSection}

## If something fails

- **Capability not found / not callable** → the registry changed; tell the user to re-create and re-save this workflow.
- **\`bridge_required\`** → ask for the file's real Mac path and retry.
- **\`3lo_required\`** → call \`authenticate_aps_3lo\`, then retry the same step.
- **Step \`failed\`** → surface the \`reportUrl\` from \`get_workflow_status\` and offer to re-run.

---
_Recipe frozen ${manifest.created_at} · ${manifest.steps.length} step(s) · ${manifest.generator}_
`;
    return md;
}
